var e=[{id:`L3_1`,type:`dialog`,speaker:`TAO_NPC_ACADEMY_NAME`,text:{KOREA:`큭?!`,JPN:`くっ！？`,ENG:`Kgh?!`,TWN:`唔？！`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`TAO_NPC_ACADEMY_NAME`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`TAO_NPC_ACADEMY_NAME`,text:{KOREA:`엘릭서의 효력을 최대한 끌어올렸는데도 버티는 게 한계라니.`,JPN:`エリクサーの効力を最大限まで引き上げたのに、凌ぐのがやっとだなんて。`,ENG:`I maximized the effects of the Elixir, and yet, I am barely able to stand on my two feet.`,TWN:`在將聖水的效果發揮到極致的情況下也撐得很勉強呢。`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`TAO_NPC_ACADEMY_NAME`,face:`UNIT_SURPRISE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`TAO_NPC_ACADEMY_NAME`,text:{KOREA:`부상을 입고도 어떻게 저런 힘이…?!`,JPN:`ボロボロの身体で、いったいどうやってここまでを力を……！？`,ENG:`How can she be so powerful even with all those wounds...?!`,TWN:`為什麼傷成那樣力氣還…？！`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`TAO_NPC_ACADEMY_NAME`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`FATHER_CLAN_BLACK_NULL`,text:{KOREA:`내가 널 중용하지 않는 것이 마음에 들지 않느냐?`,JPN:`私がお前を重用視しないことが不満か？`,ENG:`Are you displeased with my not using you?`,TWN:`你在生氣我沒有重用你嗎？`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:null,text:{KOREA:`이유를 알고 싶습니다. 제가 임무를 보다 완벽하게 해내지 못했기 때문입니까?`,JPN:`理由を知りたいのです。私の任務遂行がより完璧になれば良いのでしょうか？`,ENG:`I wish to know why. Was it because I could not execute my missions with perfection?`,TWN:`我想知道原因，是因為我辦事不力嗎？`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`FATHER_CLAN_BLACK_NULL`,text:{KOREA:`너는 내가 거두기 전부터 누구보다 차가운 심장을 가지고 있었다.`,JPN:`お前は私が引き取る以前から、誰よりも冷たい心を持っておった。`,ENG:`Your heart was colder than anyone's since before I took you in.`,TWN:`在我收留你之前，你的心就已經比任何人都還要冷酷。`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`FATHER_CLAN_BLACK_NULL`,text:{KOREA:`어쩌면, 널 다스릴 수 있는 건 흑동이 가르치는 냉철함이 아닐 지도 모른다는 생각이 들더구나.`,JPN:`もしかすると、お前を導けるのは黒東が持つ冷徹さではないかと思っておる。`,ENG:`It struck my mind that Black East's teachings of ruthlessness might not be enough to control you.`,TWN:`我就想，或許能夠管束你的，不是黑東所教導的冷血。`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:null,text:{KOREA:`저에겐 사부님의 가르침이 전부입니다.`,JPN:`私は師匠からの教えしか欲しくありません。`,ENG:`Your teachings are everything to me, master.`,TWN:`對我來說，師父的教導就是一切。`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:null,text:{KOREA:`그러니, 어떻게 해야 하는지 가르쳐주십시오.`,JPN:`ですから、どうすれば良いか教えてください。`,ENG:`So please, instruct me on what to do.`,TWN:`所以，請告訴我，我該怎麼辦。`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`FATHER_CLAN_BLACK_NULL`,text:{KOREA:`너에게 이름을 주마.`,JPN:`ではお前に名前を授けよう。`,ENG:`I shall give you a name.`,TWN:`我要給你名字。`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`FATHER_CLAN_BLACK_NULL`,text:{KOREA:`이것이 내 마지막 가르침이니, 잘 간직하거라.`,JPN:`これは私の最後の教えだ。大事にするといい。`,ENG:`Cherish it, as it will be my last teaching.`,TWN:`這是我最後的教導，你要收好它。`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`PRESIDENT_SCHOOL_NULL_NULL`,text:{KOREA:`시엘!`,JPN:`シエルさん！`,ENG:`Ciel!`,TWN:`希爾！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`……!`,JPN:`……！`,ENG:`...!`,TWN:`……！`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`…학생회장?`,JPN:`……生徒会長？`,ENG:`...Ms. President?`,TWN:`…學生會長？`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`PRESIDENT_SCHOOL_NULL_NULL`,text:{KOREA:`그 이상 계속하면, 그 자는 죽습니다.`,JPN:`それ以上続けると、その者は死んでしまいます。`,ENG:`He will die if you continue.`,TWN:`你再不住手的話他會死的。`},stage:{bg:`PRISON_NIGHT`,slots:{L:null,C:{char_id:`PRESIDENT_SCHOOL_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};